	public override void Action(RuleContext _localctx, int ruleIndex, int actionIndex) {
		switch (ruleIndex) {
		case 503 : DEFINED_TOKEN_action(_localctx, actionIndex); break;
		case 505 : HD_NEWLINE_action(_localctx, actionIndex); break;
		case 506 : UNDEFINED_TOKEN_action(_localctx, actionIndex); break;
		case 508 : HU_NEWLINE_action(_localctx, actionIndex); break;
		case 510 : IF_TOKEN_action(_localctx, actionIndex); break;
		case 511 : I_HASHIF_action(_localctx, actionIndex); break;
		case 512 : I_HASHENDIF_action(_localctx, actionIndex); break;
		}
	}
	private void DEFINED_TOKEN_action(RuleContext _localctx, int actionIndex) {
		switch (actionIndex) {
		case 0: 
		        DefinedSymbols.Add(Text);
		     break;
		}
	}
	private void HD_NEWLINE_action(RuleContext _localctx, int actionIndex) {
		switch (actionIndex) {
		case 3: PopMode(); break;
		}
	}
	private void UNDEFINED_TOKEN_action(RuleContext _localctx, int actionIndex) {
		switch (actionIndex) {
		case 1: 
		        DefinedSymbols.Remove(Text);
		     break;
		}
	}
	private void HU_NEWLINE_action(RuleContext _localctx, int actionIndex) {
		switch (actionIndex) {
		case 4: PopMode(); break;
		}
	}
	private void IF_TOKEN_action(RuleContext _localctx, int actionIndex) {
		switch (actionIndex) {
		case 2: 
		        if (DefinedSymbols.Contains(Text)) {
		            /*
		            In this case DEFINED_TOKEN is in fact defined so we get
		            back into the mode we were in before the pushMode that 
		            brought us here.
		            */
		            PopMode();
		        } else {
		            PushMode(IGNORE_MODE);
		        }
		     break;
		}
	}
	private void I_HASHIF_action(RuleContext _localctx, int actionIndex) {
		switch (actionIndex) {
		case 5: PushMode(HASHIF_MODE); break;
		}
	}
	private void I_HASHENDIF_action(RuleContext _localctx, int actionIndex) {
		switch (actionIndex) {
		case 6: PopMode(); break;
		case 7: PopMode(); break;
		}
	}

